arguments.command:
cd /tmp/sv-bfb291056821488197b4008596404cd4 && aarch64-linux-gnu-nm -D libmonosgen-2.0.so.dbg 2>/dev/null | awk '{print $1, $3}' | sort | awk -v a1="0x2f4b20" -v a2="0x2f4c84" '
BEGIN { target[1]=strtonum(a1); target[2]=strtonum(a2) }
{ addr=strtonum("0x"$1); name=$2; addrs[NR]=addr; names[NR]=name }
END {
  for(t=1; t<=2; t++) {
    best=""; bestaddr=0;
    for(i=1; i<=NR; i++) {
      if(addrs[i] <= target[t] && addrs[i] > bestaddr) { bestaddr=addrs[i]; best=names[i] }
    }
    printf "0x%x -> %s+0x%x\n", target[t], best, target[t]-bestaddr
  }
}'

